const input = $input.first() ? $input.first().json : {};
const body = (input && input.body) || input || {};
return [{
  json: {
    nome_cenario: body.nome_cenario || ('Forecast ' + (body.ano_previsao || 2026)),
    descricao: body.descricao || '',
    ano_base: parseInt(body.ano_base, 10) || 2025,
    ano_previsao: parseInt(body.ano_previsao, 10) || 2026
  }
}];

const items = $input.all().map(i => i.json);
const xlsx = items.filter(f => {
  const name = (f.name || '').toLowerCase();
  const mime = (f.mimeType || '').toLowerCase();
  return name.endsWith('.xlsx') || mime.includes('spreadsheetml') || mime.includes('vnd.google-apps.spreadsheet');
});
if (xlsx.length === 0) {
  throw new Error('Nenhuma planilha .xlsx encontrada na pasta do Google Drive.');
}
xlsx.sort((a, b) => {
  const da = new Date(a.modifiedTime || a.createdTime || 0).getTime();
  const db = new Date(b.modifiedTime || b.createdTime || 0).getTime();
  return db - da;
});
const latest = xlsx[0];
return [{ json: { file_id: latest.id, file_name: latest.name, modified_time: latest.modifiedTime || null } }];

// ===== Parâmetros =====
const params = $('Validate Input').first().json;
const anoBase = Number(params.ano_base) || 2025;
const anoPrev = Number(params.ano_previsao) || 2026;

// ===== Fonte única (Merge: histórico + orçamento) =====
const rows = $input.all().map(i => i.json);

// ===== Helpers =====
const norm = (s) => (s === undefined || s === null) ? '' : String(s).trim();
const num = (v) => {
  if (typeof v === 'number') return isNaN(v) ? 0 : v;
  if (v === undefined || v === null || v === '') return 0;
  const n = parseFloat(String(v).replace(/\s/g, '').replace(',', '.'));
  return isNaN(n) ? 0 : n;
};
const round2 = (n) => Math.round((n + Number.EPSILON) * 100) / 100;
function pick(row, names) {
  const keys = Object.keys(row);
  const flat = (s) => s.toLowerCase().replace(/\s+/g, '');
  for (const n of names) {
    const k = keys.find(k => flat(k) === flat(n));
    if (k) return row[k];
  }
  for (const n of names) {
    const k = keys.find(k => k.toLowerCase().includes(n.toLowerCase()));
    if (k) return row[k];
  }
  return undefined;
}

// ===== Classifica em uma passada (histórico = tem mês; orçamento = sem mês) =====
const keyMap = {};
const budget = {};
let registrosHist = 0;
for (const r of rows) {
  const item = norm(pick(r, ['Item', 'SKU']));
  const regional = norm(pick(r, ['Regional']));
  if (!item || !regional) continue;
  const k = item + '||' + regional;
  const mes = parseInt(pick(r, ['Mês', 'Mes']), 10);
  if (mes >= 1 && mes <= 12) {
    const ano = Number(pick(r, ['Ano']));
    if (ano !== anoBase) continue;
    registrosHist++;
    const q = num(pick(r, ['Quantidade', 'Qtd', 'Qtde']));
    if (!keyMap[k]) keyMap[k] = {
      item, regional,
      descricao: norm(pick(r, ['Descrição', 'Descricao'])),
      nome_regional: norm(pick(r, ['Nome Regional', 'Nome_Regional'])),
      meses: Array(13).fill(0),
      total: 0
    };
    keyMap[k].meses[mes] += q;
    keyMap[k].total += q;
  } else {
    const val = num(pick(r, ['Orçamento Total', 'Orcamento Total', 'Orçamento', 'Orcamento', 'Total', 'Budget']));
    if (val > 0) budget[k] = (budget[k] || 0) + val;
  }
}

if (Object.keys(keyMap).length === 0) {
  return [{ json: { success: false, error: 'Nenhum dado encontrado para o ano base ' + anoBase + ' na aba Base_Histórica_de_Vendas.' } }];
}
const temOrcamento = Object.keys(budget).length > 0;

// ===== Cálculo =====
const mensal = Array.from({ length: 12 }, (_, i) => ({ mes: i + 1, previsto: 0, anterior: 0 }));
const regAgg = {};
const skuAgg = {};
let totalPrev = 0, totalAnt = 0, absErr = 0, mapeSum = 0, mapeCount = 0;

for (const k in keyMap) {
  const e = keyMap[k];
  const bud = budget[k];
  for (let m = 1; m <= 12; m++) {
    const anterior = e.meses[m];
    const season = e.total > 0 ? e.meses[m] / e.total : 1 / 12;
    const orcDist = (bud !== undefined ? bud : e.total) * season;
    const prevista = bud !== undefined ? orcDist : anterior;
    const dif = prevista - anterior;
    mensal[m - 1].previsto += prevista;
    mensal[m - 1].anterior += anterior;
    totalPrev += prevista; totalAnt += anterior; absErr += Math.abs(dif);
    if (anterior > 0) { mapeSum += Math.abs(dif) / anterior; mapeCount++; }
    if (!regAgg[e.regional]) regAgg[e.regional] = { regional: e.regional, nome_regional: e.nome_regional, previsto: 0, anterior: 0, itens: new Set() };
    regAgg[e.regional].previsto += prevista;
    regAgg[e.regional].anterior += anterior;
    regAgg[e.regional].itens.add(e.item);
    if (!skuAgg[e.item]) skuAgg[e.item] = { item: e.item, descricao: e.descricao, total_previsto: 0, total_anterior: 0 };
    skuAgg[e.item].total_previsto += prevista;
    skuAgg[e.item].total_anterior += anterior;
  }
}

const wape = totalAnt > 0 ? absErr / totalAnt : null;
const mape = mapeCount > 0 ? mapeSum / mapeCount : null;
const accuracy = wape !== null ? Math.max(0, Math.min(1, 1 - wape)) : null;

const por_regional = Object.values(regAgg).map(r => ({
  regional: r.regional, nome_regional: r.nome_regional,
  previsto: round2(r.previsto), anterior: round2(r.anterior),
  diferenca: round2(r.previsto - r.anterior), itens: r.itens.size
})).sort((a, b) => b.previsto - a.previsto);

const top_skus = Object.values(skuAgg).map(s => ({
  item: s.item, descricao: s.descricao,
  total_previsto: round2(s.total_previsto), total_anterior: round2(s.total_anterior),
  crescimento_percentual: s.total_anterior > 0 ? round2((s.total_previsto - s.total_anterior) / s.total_anterior * 100) : 0
})).sort((a, b) => b.total_previsto - a.total_previsto);

mensal.forEach(x => { x.previsto = round2(x.previsto); x.anterior = round2(x.anterior); });

const src = $('Pick Latest XLSX').first().json;
return [{ json: {
  success: true,
  source: { file_id: src.file_id, file_name: src.file_name, modified_time: src.modified_time },
  cenario: { nome: params.nome_cenario, descricao: params.descricao, ano_base: anoBase, ano_previsao: anoPrev, base_orcamento: temOrcamento },
  kpis: {
    total_previsto: round2(totalPrev),
    total_anterior: round2(totalAnt),
    mape: mape,
    wape: wape,
    forecast_accuracy: accuracy,
    skus: Object.keys(skuAgg).length,
    registros_base: registrosHist
  },
  mensal,
  por_regional,
  top_skus
} }];
